const items = $input.all();
// Rescatamos los datos del inicio
const webhookData = $('Receptor Whatsapp Archivos').first().json.body;

for (let i = 0; i < items.length; i++) {
  const base64Data = webhookData.fileData;
  const fileName = webhookData.fileName;
  const mimeType = webhookData.mimeType || 'image/jpeg';
  // RESCATAMOS EL LINK AQUÍ:
  const linkArchivo = webhookData.link_archivo; 

  items[i].binary = {
    data: {
      data: base64Data,
      fileName: fileName,
      mimeType: mimeType,
    }
  };

  // Pasamos el link al JSON de este nodo para que Sheets lo vea
  items[i].json.link_archivo = linkArchivo;
}

return items;

const rawText = $json.content.parts[0].text;
let data = {};

try {
  // Intentamos limpiar y parsear el JSON
  const cleanJson = rawText.replace(/```json|```/g, "").trim();
  data = JSON.parse(cleanJson);
} catch (e) {
  // Si falla el parseo (porque Gemini mandó texto normal), creamos un objeto por defecto
  data = {
    error: "Imagen borrosa o no legible",
    detalle: rawText.substring(0, 50) + "...", // Guardamos el inicio de la excusa de Gemini
    nombre_hoja_destino: "REVISAR", // Para que sepas que falló
    anio_documento: new Date().getFullYear()
  };
}

// Mantenemos tus campos adicionales
const mesNombre = data.nombre_hoja_destino || "REVISAR";
const anioDoc = data.anio_documento || "";

return {
  ...data,
  nombre_hoja_destino: mesNombre,
  anio_documento: anioDoc,
  id_final: "ID-" + Date.now(),
  link_archivo: $node["Google Drive"].json["webViewLink"] || "https://drive.google.com/uc?id=" + $node["Google Drive"].json["id"]
};
